	.SBTTL	INTROVOITPOBVOITX=	130		; bullePOBVOITY=	8LGBVOITX=	497LGBVOITY=	162POVOITX	=	29		; voiturePOVOITY	=	264LGVOITX	=	149LGVOITY	=	50LGVOITI	=	LGVOITX/8+1POGARX	=	468		; garagePOGARY	=	POVOITYLGGARX	=	LGVOITXLGGARY	=	LGVOITY;--------\\; VOITURE >;========/VOITURE:	LOAD.L	A3,#R16"TXIMAS2	CALL	AFIMAGE	JUMP,NE 90$	CALL	OPEVOITURE	; A4 <-- ^matrice voiture	JUMP,NE 90$	LOAD.L	D4,#H'10000*203+188	CALL	PMOUSE	LOAD.W	D3,#ICOMAIN	CALL	ICOMOUSE	; la souris devient une main	CALL	CLRFIFO		; vide le FIFO du clavier	LOAD.W	D6,#POVOITY	SWAP.W	D6	LOAD.W	D6,#POVOITX	; D6 <-- position de la voiture10$:	LIB	?GETCAR		; attend souris ...	COMP.W	D3,#KEYMGR	JUMP,EQ 10$	COMP.W	D3,#KEYMMR	JUMP,EQ 10$	COMP.W	D3,#KEYMDR	JUMP,EQ 10$	COMP.W	D3,#KEYMGP	JUMP',EQ 20$	COMP.W	D3,#KEYMMP	JUMP',EQ 20$	COMP.W	D3,#KEYMDP	JUMP',EQ 20$;;?	LOAD.B	D3,#BIPERR;;?	.W	LIB,?BEEP	JUMP	10$16$:	LOAD.B	D3,#BIPERR	LIB	?BEEP	CALL	ERRVOITURE	JUMP	10$20$:				; clic =>	LOAD.L	A3,#R16"ERVOIT1	LIB	?IFMOUSE	JUMP,NE 16$	ADD.W	D4,#GCICX/2	JUMP,LO 16$	SWAP.W	D4	ADD.W	D4,#GCICY/2	JUMP,LO 16$	SWAP.W	D4	LOAD.L	D3,D6	SUB.W	D4,D3	JUMP,LO 16$	COMP.W	D4,#LGVOITX	JUMP,HS 16$	SWAP.W	D3	SWAP.W	D4	SUB.W	D4,D3	JUMP,LO 16$	COMP.W	D4,#LGVOITY	JUMP,HS 16$	SWAP.W	D4	LOAD.L	D5,D4		; D5 <-- correction30$:	LIB	?GETKEY		; attend souris ...	COMP.W	D3,#KEYMPO	JUMP,NE 50$	LIB	?IFMOUSE	JUMP,NE 30$	ADD.W	D4,#GCICX/2	JUMP,LO 30$	SWAP.W	D4	ADD.W	D4,#GCICY/2	JUMP,LO 30$	SWAP.W	D4	SUB.W	D4,D5	SWAP.W	D4	SWAP.W	D5	SUB.W	D4,D5	SWAP.W	D4	SWAP.W	D5	TEST.W	D4	JUMP',GE 40$	CLR.W	D440$:	LOAD.W	D3,(A0)+ODFDX	SUB.W	D3,#LGVOITX	COMP.W	D4,D3	JUMP',LO 42$	LOAD.W	D4,D342$:	SWAP.W	D4	COMP.W	D4,#POVOITY-50	JUMP',GE 44$	LOAD.W	D4,#POVOITY-5044$:	LOAD.W	D3,(A0)+ODFDY	SUB.W	D3,#LGVOITY	COMP.W	D4,D3	JUMP',LO 46$	LOAD.W	D4,D346$:	SWAP.W	D4	EX.L	D4,D6	CALL	MOVVOITURE	; efface l'ancienne voiture	LOAD.L	D4,D6	CALL	MOVVOITURE	; dessine la nouvelle voiture	JUMP	30$50$:	LOAD.L	A3,#R16"ERVOIT2	LOAD.L	D4,D6	ADD.W	D4,#LGVOITX/2	SUB.W	D4,#POGARX	; centre dans le garage ?	JUMP,LO 16$	COMP.W	D4,#LGGARX	JUMP,HS 16$	SWAP.W	D4	ADD.W	D4,#LGVOITY/2	SUB.W	D4,#POGARY	JUMP,LO 16$	COMP.W	D4,#LGGARY	JUMP,HS 16$	LOAD.L	D4,D6	CALL	MOVVOITURE	; efface l'ancienne voiture	LOAD.W	D4,#POGARY	SWAP.W	D4	LOAD.W	D4,#POGARX	CALL	MOVVOITURE	; dessine la voiture pile dans le garage	LOAD.B	D3,#BIPDONE	LIB	?BEEP	LOAD.L	A3,#R16"ERVOIT3	CALL	ERRVOITURE	LOAD.L	D3,#-1	LOAD.L	D4,D3	LIB	?DRMDEF	LOAD.W	D3,#POGARY-24	SWAP.W	D3	LOAD.W	D3,#POGARX-14	LOAD.W	D4,#LGGARY+24+16	SWAP.W	D4	LOAD.W	D4,#LGGARX+14+14	LOAD.W	D2,#INVDOT	LOAD.W	D1,#10*270$:	PUSH.W	D4	LOAD.W	D4,#4	NTREL	?DELMS	POP.W	D4	LIB	?DRMATRIX	DEC.W	D1	JUMP,NE 70$	LOAD.W	D4,#50*3	NTREL	?DELMS	CALL	CLOVOITURE	; libre la mmoire	CLR.W	D3	CALL	ICOMOUSE90$:	RET;-----------\\; ERRVOITURE >;-----------/; Affiche un message dans la bulle.; in	A3.L	^message; out	-; mod	D7.WERRVOITURE:	PUSHM.L	D2..D4,A3	LOAD.L	D3,#-1	LOAD.L	D4,D3	LIB	?DRMDEF	LOAD.W	D3,#POBVOITY	SWAP.W	D3	LOAD.W	D3,#POBVOITX	LOAD.W	D4,#LGBVOITY	SWAP.W	D4	LOAD.W	D4,#LGBVOITX	LOAD.W	D2,#SETDOT	LIB	?DRMATRIX	; efface la bulle	LIB	?AFTIM	.B	USEGC,GCTBF,GCTBS,GCTBT	.B	MODCAR	.B	PENDOT!CLRDOT	.B	0	.EVEN	ADD.W	D3,#50	SWAP.W	D3	ADD.W	D3,#24	SWAP.W	D340$:	LIB	?SETCURS	SWAP.W	D3	ADD.W	D3,(A0)+ODFCY	SWAP.W	D3	LIB	?AFTEXT	TEST.B	(A3)	JUMP,NE 40$	LIB	?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT	.B	MODCAR	.B	SETDOT	.B	0	.EVEN	POPM.L	D2..D4,A3	RET;-----------\\; OPEVOITURE >;-----------/; Met la matrice de la voiture en mmoire.; in	-; out	A4.L	^matrice voiture;	D7.W	erreur; mod	D7.W, A4.LOPEVOITURE:	PUSHM.L	D1,D3,D4,A3	LOAD.L	D4,#LGVOITI*LGVOITY	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM	JUMP,NE 90$	LOAD.L	A3,A420$:	CLR.B	(A3+)	DEC.W	D4	JUMP,NE 20$	LOAD.L	A3,#(A6)+OBUDIS	LOAD.W	(A3)+0,#DRAWRASTER	LOAD.W	(A3)+2,#POVOITX	LOAD.W	(A3)+4,#POVOITY	CLR.L	(A3)+6	CLR.W	(A3)+10	CLR.L	(A3)+12	LOAD.L	(A3)+16,A4	LOAD.W	(A3)+20,#LGVOITI	LOAD.W	(A3)+22,#LGVOITX	LOAD.W	(A3)+24,#LGVOITY	LOAD.B	(A3)+26,#SETDOT	LOAD.W	D3,#1+26	LIB	?STRING	LOAD.L	A3,A4	LOAD.W	D4,#(LGVOITI*LGVOITY)-150$:	NOT.B	(A3+)		; inverse la voiture	DECJ.W,NMO D4,50$	CLR.W	D790$:	POPM.L	D1,D3,D4,A3	TEST.W	D7		; retour EQ/NE	RET;-----------\\; MOVVOITURE >;-----------/; Inverse la voiture dans l'cran.; in	A4.L	^matrice voiture;	D4.L	position du coin sup/gauche; out	-; mod	D7.WMOVVOITURE:	PUSHM.L	D3,D4,A3	LOAD.L	A3,#(A6)+OBUDIS	LOAD.W	(A3)+0,#DRAWRASTER	CLR.L	(A3)+2	LOAD.L	(A3)+6,A4	LOAD.W	(A3)+10,#LGVOITI	SWAP.W	D4	LOAD.L	(A3)+12,D4	CLR.L	(A3)+16	CLR.W	(A3)+20	LOAD.W	(A3)+22,#LGVOITX	LOAD.W	(A3)+24,#LGVOITY	LOAD.B	(A3)+26,#INVDOT	LOAD.W	D3,#1+26	LIB	?STRING	POPM.L	D3,D4,A3	RET;-----------\\; CLOVOITURE >;-----------/; Libre la mmoire pour la matrice de la voiture.; in	A4.L	^matrice voiture; out	-; mod	D7.WCLOVOITURE:	PUSH.W	D1	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM	POP.W	D1	RETERVOIT1:	.ASCIZ	" "	.ASCIZ	"  Non non, pas comme cela !"	.ASCIZ	"  Il faut cliquer avec la souris"	.ASCIZ	"  dans la voiture."	.ASCIZ	" "	.ASCIZ	"  Visez mieux ..."	.B	0ERVOIT2:	.ASCIZ	"Vous avez relch le bouton de la"	.ASCIZ	"souris alors que la voiture n'tait"	.ASCIZ	"pas encore dans son garage !"	.ASCIZ	" "	.ASCIZ	"Maintenez press le bouton pendant"	.ASCIZ	"que vous bougez la souris ..."	.B	0ERVOIT3:	.ASCIZ	" "	.ASCIZ	" "	.ASCIZ	"            Bravo !"	.ASCIZ	" "	.ASCIZ	"         C'est russi."	.B	0	.EVEN	.END